def t(id, name, tagline, desc, keywords, category, faqs=None, related=None, vol=5000):
    slug = id
    return {
        "id": id, "slug": slug, "name": name, "tagline": tagline,
        "description": desc[:160], "keywords": keywords, "category": category,
        "faqs": faqs or [
            {"q": f"Is the {name} free?", "a": f"Yes, completely free. No signup required. Works entirely in your browser."},
            {"q": f"How accurate is the {name}?", "a": f"This tool uses traditional {category} methods and formulas for its calculations."}
        ],
        "relatedTools": related or [], "priority": round(min(0.9, 0.5 + vol/500000), 2),
        "monthlySearches": vol, "evergreen": True
    }

