os.makedirs(os.path.join(BASE, "tools"), exist_ok=True)
total = 0
for cat_id, tools in TOOLS.items():
    path = os.path.join(BASE, "tools", f"{cat_id}.json")
    with open(path, "w") as f:
        json.dump(tools, f, indent=2)
